5320	// executeLoopFailedRoutesKey is the bead Extra key holding the JSON-encoded
5321	// list of (provider, model, actual_power) tuples that have failed with a
5322	// provider-connectivity error. Subsequent routing-evidence events read this
5323	// list to populate fallback_chain so post-hoc review can see what was
5324	// excluded; the power-hint nudge on the same bead biases fizeau's next
5325	// RouteRequest off the failed power tier when a ladder is available.
5326	const executeLoopFailedRoutesKey = "work-failed-routes"
5327	
5328	// failedRoutesMaxEntries is the FIFO ring cap on the work-failed-routes list.
5329	// When the list is full, the oldest entry is evicted on insert.
5330	const failedRoutesMaxEntries = 32
5331	
5332	// RouteExclusionWindow is the time window within which a recorded
5333	// work-failed-routes entry suppresses a (provider, model) pair in
5334	// the next RouteRequest.ExcludedRoutes payload. Entries older than this
5335	// window remain in the bead's audit list but do not constrain routing,
5336	// allowing recovery once the provider returns.
5337	const RouteExclusionWindow = time.Hour
5338	
5339	// FailedRouteEntry is the JSON shape persisted under executeLoopFailedRoutesKey.
5340	// Exported so external callers (test helpers, tooling) can decode it without
5341	// duplicating the schema.
5342	type FailedRouteEntry struct {
5343		Provider    string `json:"provider"`
5344		Model       string `json:"model,omitempty"`
5345		ActualPower int    `json:"actual_power,omitempty"`
5346		Reason      string `json:"reason,omitempty"`
5347		// Endpoint is the concrete provider URL the failed dispatch dialed
5348		// (e.g. http://vidar:1235/v1/chat/completions), parsed from the worker's
5349		// transport error. Actionable route fact for operators diagnosing an
5350		// unreachable endpoint; empty when no URL could be parsed.
5351		Endpoint string `json:"endpoint,omitempty"`
5352		// TimeoutClass is the transport failure class parsed from the error
5353		// (e.g. "i/o timeout", "connection refused", "no route to host"). It
5354		// distinguishes a down endpoint (connection refused) from an unreachable
5355		// one (i/o timeout / no route to host) so remediation can be targeted.
5356		TimeoutClass string `json:"timeout_class,omitempty"`
5357		At           string `json:"at,omitempty"`
5358		Count        int    `json:"count,omitempty"`
5359	}
5360	
5361	// readFailedRoutes decodes the failed-route list from a bead's Extra. Returns
5362	// nil when absent or malformed; never errors. Transparently normalizes legacy
5363	// data: collapses duplicates by (provider, model) and caps at failedRoutesMaxEntries.
5364	func readFailedRoutes(extra map[string]any) []FailedRouteEntry {
5365		if len(extra) == 0 {
5366			return nil
5367		}
5368		raw, ok := extra[executeLoopFailedRoutesKey]
5369		if !ok {
5370			return nil
5371		}
5372		encoded, err := json.Marshal(raw)
5373		if err != nil {
5374			return nil
5375		}
5376		var entries []FailedRouteEntry
5377		if err := json.Unmarshal(encoded, &entries); err != nil {
5378			return nil
5379		}
5380		return normalizeFailedRoutes(entries)
5381	}
5382	
5383	// normalizeFailedRoutes collapses duplicate (provider, model) entries keeping
5384	// the newest At timestamp and summing counts, then caps the list at
5385	// failedRoutesMaxEntries by evicting oldest entries (FIFO). Used by
5386	// readFailedRoutes to transparently migrate legacy bead data on read.
5387	func normalizeFailedRoutes(entries []FailedRouteEntry) []FailedRouteEntry {
5388		if len(entries) == 0 {
5389			return entries
5390		}
5391		type key struct{ provider, model string }
5392		index := make(map[key]int, len(entries))
5393		collapsed := make([]FailedRouteEntry, 0, len(entries))
5394		for _, e := range entries {
5395			k := key{e.Provider, e.Model}
5396			if i, ok := index[k]; ok {
5397				existingCount := collapsed[i].Count
5398				if existingCount == 0 {
5399					existingCount = 1
5400				}
5401				ec := e.Count
5402				if ec == 0 {
5403					ec = 1
5404				}
5405				if e.At > collapsed[i].At {
5406					endpoint := e.Endpoint
5407					if endpoint == "" {
5408						endpoint = collapsed[i].Endpoint
5409					}
5410					timeoutClass := e.TimeoutClass
5411					if timeoutClass == "" {
5412						timeoutClass = collapsed[i].TimeoutClass
5413					}
5414					collapsed[i] = FailedRouteEntry{
5415						Provider:     e.Provider,
5416						Model:        e.Model,
5417						ActualPower:  e.ActualPower,
5418						Reason:       e.Reason,
5419						Endpoint:     endpoint,
5420						TimeoutClass: timeoutClass,
5421						At:           e.At,
5422						Count:        existingCount + ec,
5423					}
5424				} else {
5425					collapsed[i].Count = existingCount + ec
5426					if collapsed[i].Endpoint == "" {
5427						collapsed[i].Endpoint = e.Endpoint
5428					}
5429					if collapsed[i].TimeoutClass == "" {
5430						collapsed[i].TimeoutClass = e.TimeoutClass
5431					}
5432				}
5433			} else {
5434				index[k] = len(collapsed)
5435				c := e
5436				if c.Count == 0 {
5437					c.Count = 1
5438				}
5439				collapsed = append(collapsed, c)
5440			}
5441		}
5442		if len(collapsed) > failedRoutesMaxEntries {
5443			collapsed = collapsed[len(collapsed)-failedRoutesMaxEntries:]
5444		}
5445		return collapsed
5446	}
