10	func readinessDecisionBody(ruleID, reason, decisionSource, policyMode, decision, suggestedAction string, extra map[string]any) map[string]any {
11		body := make(map[string]any, 7+len(extra))
12		add := func(key, value string) {
13			if value = strings.TrimSpace(value); value != "" {
14				body[key] = value
15			}
16		}
17		add("rule_id", ruleID)
18		add("reason", reason)
19		add("decision_source", decisionSource)
20		add("policy_mode", policyMode)
21		add("decision", decision)
22		add("suggested_action", suggestedAction)
23		if fingerprint := readinessDecisionFingerprint(ruleID, reason, decisionSource, policyMode, decision, suggestedAction); fingerprint != "" {
24			body["fingerprint"] = fingerprint
25		}
26		for k, v := range extra {
27			if v != nil {
28				body[k] = v
29			}
30		}
31		return body
32	}
33	
34	func readinessDecisionBodyJSON(ruleID, reason, decisionSource, policyMode, decision, suggestedAction string, extra map[string]any) string {
35		body, _ := json.Marshal(readinessDecisionBody(ruleID, reason, decisionSource, policyMode, decision, suggestedAction, extra))
36		return string(body)
37	}
38	
39	func readinessDecisionFingerprint(ruleID, reason, decisionSource, policyMode, decision, suggestedAction string) string {
40		parts := []string{
41			strings.ToLower(strings.TrimSpace(ruleID)),
42			strings.ToLower(strings.TrimSpace(reason)),
43			strings.ToLower(strings.TrimSpace(decisionSource)),
44			strings.ToLower(strings.TrimSpace(policyMode)),
45			strings.ToLower(strings.TrimSpace(decision)),
46			strings.ToLower(strings.TrimSpace(suggestedAction)),
47		}
48		if strings.Join(parts, "") == "" {
49			return ""
50		}
51		sum := sha256.Sum256([]byte(strings.Join(parts, "\x00")))
52		return hex.EncodeToString(sum[:])
53	}
