127	func jsonKindName(first byte) string {
128		switch first {
129		case '{':
130			return "object"
131		case '[':
132			return "array"
133		case '"':
134			return "string"
135		case 't', 'f':
136			return "bool"
137		case 'n':
138			return "null"
139		default:
140			return "number"
141		}
142	}
