228	func decodeReadinessStringListField(data []byte, fieldName string, splitLines bool) ([]string, error) {
229		trimmed := strings.TrimSpace(string(data))
230		if trimmed == "" || trimmed == "null" {
231			return nil, nil
232		}
233		switch trimmed[0] {
234		case '[':
235			var items []string
236			if err := json.Unmarshal(data, &items); err != nil {
237				return nil, err
238			}
239			return normalizeReadinessStringList(items), nil
240		case '"':
241			var item string
242			if err := json.Unmarshal(data, &item); err != nil {
243				return nil, err
244			}
245			if splitLines {
246				return normalizeReadinessStringList(strings.Split(item, "\n")), nil
247			}
248			return normalizeReadinessStringList([]string{item}), nil
249		default:
250			return nil, fmt.Errorf("%s must be a string or string array", fieldName)
251		}
252	}
