442	// NewPreClaimIntakeHookWithLogVerbose constructs the pre-claim intake hook and
443	// prints the full prompt only when promptVerbose is true.
444	func NewPreClaimIntakeHookWithLogVerbose(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner, log io.Writer, promptVerbose bool) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
445		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
446			if ctx != nil {
447				if err := ctx.Err(); err != nil {
448					return PreClaimIntakeResult{}, err
449				}
450			}
451			if strings.TrimSpace(projectRoot) == "" {
452				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
453			}
454			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
455				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: %w", err)
456			}
457			if store == nil {
458				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
459			}
460	
461			b, err := store.Get(beadID)
462			if err != nil {
463				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
464			}
465	
466			prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
467			if err != nil {
468				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
469			}
470	
471			runtime := AgentRunRuntime{
472				Prompt:        prompt,
473				PromptSource:  PreClaimIntakePromptSource,
474				Output:        log,
475				WorkLogPhase:  "readiness",
476				Correlation:   map[string]string{"bead_id": beadID},
477				ClearProfile:  true,
478				ClearMinPower: true,
479			}
480			runtime.ClearMaxPower = true
481			logPreClaimIntakePrompt(log, projectRoot, beadID, prompt, runtime, promptVerbose)
482			applyLifecycleHookRouting(ctx, projectRoot, svc, runner, rcfg, &runtime, SelectStandardProfile)
483			logPreClaimIntakeRoute(log, beadID, runtime, promptVerbose)
484			payload, err := dispatchPreClaimIntakePayload(ctx, projectRoot, svc, runner, rcfg, runtime)
485			if err != nil {
486				return PreClaimIntakeResult{
487					Outcome: PreClaimIntakeError,
488					Detail:  preClaimIntakeRouteUnavailableDetail(err),
489				}, nil
490			}
491	
492			return decodePreClaimIntakePayloadResultWithMode(payload, rcfg.BeadQualityMode())
493		}
494	}
