496	func logPreClaimIntakePrompt(w io.Writer, projectRoot, beadID, prompt string, runtime AgentRunRuntime, verbose bool) {
497		if w == nil || !verbose {
498			return
499		}
500		logDir := ResolveLogDir(projectRoot, "")
501		_, _ = fmt.Fprintf(w, "readiness prompt %s: sent source=%s bytes=%d session_logs=%s\n", beadID, PreClaimIntakePromptSource, len(prompt), logDir)
502		_, _ = fmt.Fprintf(w, "readiness prompt %s begin\n%s", beadID, truncatePreClaimIntakePromptForLog(prompt))
503		if !strings.HasSuffix(prompt, "\n") {
504			_, _ = fmt.Fprintln(w)
505		}
506		_, _ = fmt.Fprintf(w, "readiness prompt %s end\n", beadID)
507	}
