535	func truncatePreClaimIntakePromptForLog(prompt string) string {
536		const limit = 32 * 1024
537		if len(prompt) <= limit {
538			return prompt
539		}
540		const marker = "\n...[readiness prompt truncated in worker log; full prompt is in the service session log]...\n"
541		head := (limit - len(marker)) / 2
542		tail := limit - len(marker) - head
543		if head <= 0 || tail <= 0 {
544			return prompt[:limit]
545		}
546		return prompt[:head] + marker + prompt[len(prompt)-tail:]
547	}
