686	func normalizePreClaimIntakeRewriteFields(fields []string) []string {
687		if len(fields) == 0 {
688			return nil
689		}
690		seen := make(map[string]struct{}, len(fields))
691		out := make([]string, 0, len(fields))
692		for _, field := range fields {
693			field = strings.ToLower(strings.TrimSpace(field))
694			if field == "" {
695				continue
696			}
697			if _, ok := seen[field]; ok {
698				continue
699			}
700			seen[field] = struct{}{}
701			out = append(out, field)
702		}
703		return out
704	}
