862	func malformedReadinessChecksDetail(checks preClaimReadinessChecksPayload) string {
863		detail := strings.TrimSpace(checks.Malformed)
864		if detail == "" {
865			detail = "readiness_checks must be an object or array"
866		}
867		if evidence := strings.TrimSpace(checks.Evidence); evidence != "" {
868			detail += ": " + strconv.Quote(evidence)
869		}
870		return detail
871	}
872	
873	func readinessCheckEvidence(checks []preClaimReadinessCheck) string {
874		for _, check := range checks {
875			if strings.ToLower(strings.TrimSpace(string(check.Verdict))) != "fail" {
876				continue
877			}
878			if evidence := strings.TrimSpace(check.Evidence); evidence != "" {
879				return evidence
880			}
881		}
882		return ""
883	}
884	
885	func readinessDetailWithReason(classified ReadinessClassificationResult, detail string) string {
886		detail = strings.TrimSpace(detail)
887		reason := strings.TrimSpace(classified.Reason)
888		if reason == "" {
889			return detail
890		}
891		if detail == "" {
892			return reason
893		}
894		if strings.Contains(strings.ToLower(detail), strings.ToLower(reason)) {
895			return detail
896		}
897		return reason + ": " + detail
898	}
899	
900	func firstNonEmptyReadinessDetail(values ...string) string {
901		for _, value := range values {
902			if trimmed := strings.TrimSpace(value); trimmed != "" {
903				return trimmed
904			}
905		}
906		return ""
907	}
