909	func hasPreClaimIntakeRewrite(rewrite PreClaimIntakeRewrite) bool {
910		return strings.TrimSpace(rewrite.Description) != "" ||
911			strings.TrimSpace(rewrite.Acceptance) != "" ||
912			len(rewrite.ChangedFields) > 0
913	}
