915	func normalizeReadinessEstimatedDifficulty(raw string) string {
916		switch strings.ToLower(strings.TrimSpace(raw)) {
917		case string(escalation.DifficultyEasy):
918			return string(escalation.DifficultyEasy)
919		case string(escalation.DifficultyMedium):
920			return string(escalation.DifficultyMedium)
921		case string(escalation.DifficultyHard):
922			return string(escalation.DifficultyHard)
923		default:
924			return ""
925		}
