5103	// isValidImplementationAttempt reports whether the given report came from a
5104	// real implementation attempt — one where the implementer had checkout context
5105	// established and a result that can be compared against the base revision for
5106	// no-progress accounting. Returns false for system failures, infrastructure
5107	// issues, intake/scheduling outcomes, review/operator-managed states, and
5108	// other non-implementation outcomes that should not consume the no-progress
5109	// retry budget or trigger long cooldowns.
5110	func isValidImplementationAttempt(report ExecuteBeadReport) bool {
5111		if report.Disrupted {
5112			return false
5113		}
5114		if isTransientOutcomeReason(report.OutcomeReason) {
5115			return false
5116		}
5117		// Extended system-failure and non-implementation outcome reasons.
5118		switch report.OutcomeReason {
5119		case "preflight_failed",
5120			"intake_block",
5121			"claim_race",
5122			"actionable_but_rewritten",
5123			"too_large_decomposed",
5124			"intake_error",
5125			"ambiguous_needs_human",
5126			FailureModeAuthError,
5127			FailureModeHarnessNotInstalled,
5128			FailureModeAgentPowerUnsatisfied,
5129			FailureModeBlockedByPassthroughConstraint,
5130			FailureModeNoEvidenceProduced,
5131			FailureModeWorktreeLost,
5132			ReadinessSystemReasonResourceExhausted,
5133			ReadinessSystemReasonRepoConcurrency,
5134			"operator_required":
5135			return false
5136		}
5137		// Operator/review status codes where the implementer did not run a full
5138		// implementation pass.
5139		switch report.Status {
5140		case ExecuteBeadStatusReviewMalfunction,
5141			ExecuteBeadStatusDeclinedNeedsDecomposition,
5142			ExecuteBeadStatusLandConflictOperatorRequired,
5143			ExecuteBeadStatusReviewTerminalBlock:
5144			return false
5145		}
5146		// Without a BaseRev the implementer never had a commit baseline.
5147		if report.BaseRev == "" {
5148			return false
5149		}
5150		return true
5151	}
