5153	func shouldSuppressNoProgress(report ExecuteBeadReport) bool {
5154		if !isValidImplementationAttempt(report) {
5155			return false
5156		}
5157		if report.ResultRev == "" {
5158			return false
5159		}
5160		return report.BaseRev == report.ResultRev
5161	}
