package agent

import (
	"fmt"
	"io"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// preClaimWarnRepeatState tracks consecutive identical pre-claim warn
// fingerprints across distinct candidate beads. When the same fingerprint
// is observed on N consecutive distinct bead IDs, the loop escalates to
// operator attention and stops looping.
type preClaimWarnRepeatState struct {
	// Fingerprint of the most recent warn (empty if no prior warn).
	Fingerprint string
	// Count of consecutive beads with the same fingerprint.
	Count int
	// DistinctBeadIDs are the bead IDs that have produced the current fingerprint.
	DistinctBeadIDs map[string]struct{}
	// ExampleDetail carries one example payload from the repeated warn.
	ExampleDetail string
}

// appendPreClaimIntakeWarning updates the pre-claim warn state tracking N
// consecutive identical fingerprints. It emits a warn event via the emit
// callback and returns true if escalation (operator attention) is warranted.
//
// When escalation returns true, the caller must emit an operator-attention
// event, set a terminal result condition, and break the drain loop.
//
// The function creates a fingerprint from the rule_id, reason, decision_source,
// policy_mode, decision, and suggested_action. It tracks distinct bead IDs
// and resets the counter when a different fingerprint is observed.
func appendPreClaimIntakeWarning(
	store BeadReader,
	emit func(eventType string, data map[string]any),
	state *preClaimWarnRepeatState,
	threshold int,
	beadID, reason, detail string,
	at time.Time,
) bool {
	if store == nil || emit == nil || state == nil || threshold <= 0 {
		return false
	}

	// Create the warn fingerprint using the same vocabulary as the
	// pre_claim_intake.warn event body.
	fingerprint := readinessDecisionFingerprint(
		"pre_claim_intake",
		reason,
		"pre_claim_intake",
		"warn-only",
		"warn",
		"continue with implementation; operator attention is reserved for explicit targeted execution",
	)

	// If this is a different fingerprint, reset the counter.
	if fingerprint != state.Fingerprint {
		state.Fingerprint = fingerprint
		state.Count = 0
		state.DistinctBeadIDs = make(map[string]struct{})
		state.ExampleDetail = ""
	}

	// Record this bead if not already seen with this fingerprint.
	if _, ok := state.DistinctBeadIDs[beadID]; !ok {
		state.Count++
		state.DistinctBeadIDs[beadID] = struct{}{}
		if state.ExampleDetail == "" {
			state.ExampleDetail = detail
		}
	}

	// Emit a warn event for this candidate.
	eventBody := readinessDecisionBody(
		"pre_claim_intake",
		reason,
		"pre_claim_intake",
		"warn-only",
		"warn",
		"continue with implementation; operator attention is reserved for explicit targeted execution",
		map[string]any{
			"bead_id": beadID,
			"detail":  detail,
		},
	)
	emit("pre_claim_intake.warn", eventBody)

	// Check escalation threshold: N consecutive distinct beads with the
	// same fingerprint.
	if state.Count >= threshold {
		return true
	}
	return false
}

// resetPreClaimWarnState clears the warn repeat state, used when a claim
// succeeds so the counter does not artificially accumulate across
// disjoint candidate sequences.
func resetPreClaimWarnState(state *preClaimWarnRepeatState) {
	if state != nil {
		state.Fingerprint = ""
		state.Count = 0
		state.DistinctBeadIDs = make(map[string]struct{})
		state.ExampleDetail = ""
	}
}

// writePreClaimWarnEscalationEvent emits the terminal operator-attention
// event when the consecutive identical warn fingerprint threshold is reached.
// The event includes the fingerprint, example detail, and count info.
func writePreClaimWarnEscalationEvent(
	emit func(eventType string, data map[string]any),
	state *preClaimWarnRepeatState,
	beadID string,
	log io.Writer,
) {
	if emit == nil || state == nil || state.Fingerprint == "" {
		return
	}

	detailText := fmt.Sprintf(
		"pre-claim warn fingerprint repeated %d times across %d distinct bead IDs",
		state.Count,
		len(state.DistinctBeadIDs),
	)

	emit("loop.operator_attention", map[string]any{
		"reason":            "preclaim_warn_repeated",
		"bead_id":           beadID,
		"detail":            detailText,
		"fingerprint":       state.Fingerprint,
		"repeat_count":      state.Count,
		"distinct_bead_ids": len(state.DistinctBeadIDs),
		"example_detail":    state.ExampleDetail,
	})

	if log != nil {
		_, _ = fmt.Fprintf(log, "operator attention: %s\n", detailText)
	}
}

