package agent

import (
	"bytes"
	"context"
	"encoding/json"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestDrainLoop_EscalatesAfterConsecutiveIdenticalPreClaimWarnFingerprint
// is AC #1: The drain loop tracks consecutive pre-claim warn outcomes by
// fingerprint and, after N (default 5) consecutive outcomes with the same
// fingerprint, emits exactly one operator-attention event containing the
// fingerprint and a single example detail/payload, then stops looping instead
// of continuing to poll.
func TestDrainLoop_EscalatesAfterConsecutiveIdenticalPreClaimWarnFingerprint(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	// Create N ready beads that will all fail intake with the same fingerprint.
	numBeads := 7
	var beadIDs []string
	for i := 0; i < numBeads; i++ {
		b := &bead.Bead{
			ID:       "ddx-preclaim-warn-test-" + string(rune(i)),
			Title:    "preclaim warn test " + string(rune(i)),
			Priority: 0,
		}
		require.NoError(t, store.Create(b))
		beadIDs = append(beadIDs, b.ID)
	}

	// Collect all events emitted during the loop.
	var eventLog bytes.Buffer
	var emittedEvents []map[string]any

	intakeCallCount := 0

	// Pre-claim intake hook that always returns the same warn fingerprint
	// for all candidates.
	intakeHook := func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
		intakeCallCount++
		return PreClaimIntakeResult{
			Outcome: PreClaimIntakeError,
			Reason:  "schema_mismatch",
			Detail:  "readiness schema validation failed",
		}, nil
	}

	// Executor that succeeds trivially so we can observe the loop's pre-claim
	// warn escalation.
	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			ResultRev: "rev",
		}, nil
	})

	opts := config.TestLoopConfigOpts{
		Assignee:                           "test-worker",
		BeadQualityLintBlockThresholdScore: 0,
	}
	rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))

	rt := ExecuteBeadLoopRuntime{
		Once:                            false,
		ProjectRoot:                     store.ProjectRoot(),
		SessionID:                       "test-session",
		WorkerID:                        "test-worker",
		Log:                             &eventLog,
		EventSink:                       &eventLog,
		PreClaimIntakeHook:              intakeHook,
		PreClaimWarnRepeatThreshold:     5, // AC threshold
		PreClaimTimeout:                 5 * time.Second,
	}

	// Wrap the event sink to capture events.
	originalSink := rt.EventSink
	var captured bytes.Buffer
	rt.EventSink = &captured

	worker := &ExecuteBeadWorker{
		Store:    store,
		Executor: executor,
	}

	result, err := worker.Run(context.Background(), rcfg, rt)

	// Decode captured events for inspection.
	lines := bytes.Split(captured.Bytes(), []byte("\n"))
	for _, line := range lines {
		if len(line) == 0 {
			continue
		}
		var event map[string]any
		if err := json.Unmarshal(line, &event); err == nil {
			emittedEvents = append(emittedEvents, event)
		}
	}

	// AC #1a: The loop must stop after escalation (not continue to poll).
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, "OperatorAttention", result.StopCondition,
		"loop must stop with OperatorAttention condition when warn threshold is reached")
	assert.NotNil(t, result.OperatorAttention,
		"loop must set OperatorAttention result when warn threshold is reached")
	assert.Equal(t, "preclaim_warn_repeated", result.OperatorAttention.Reason,
		"operator attention reason must be preclaim_warn_repeated")

	// AC #1b: Exactly one operator-attention event must be emitted with the
	// fingerprint and example detail.
	var opAttnEvents []map[string]any
	for _, event := range emittedEvents {
		if kind, ok := event["kind"].(string); ok && kind == "loop.operator_attention" {
			if reason, ok := event["reason"].(string); ok && reason == "preclaim_warn_repeated" {
				opAttnEvents = append(opAttnEvents, event)
			}
		}
	}
	assert.Equal(t, 1, len(opAttnEvents),
		"exactly one operator-attention event with preclaim_warn_repeated reason must be emitted")

	if len(opAttnEvents) > 0 {
		opAttn := opAttnEvents[0]
		assert.NotEmpty(t, opAttn["fingerprint"],
			"operator-attention event must include the repeated fingerprint")
		assert.NotEmpty(t, opAttn["example_detail"],
			"operator-attention event must include an example detail")
		assert.Equal(t, 5, int(opAttn["repeat_count"].(float64)),
			"repeat count must match the threshold (5)")
	}

	// Verify that intake hook was called fewer than numBeads times, confirming
	// the loop stopped early (not called on bead 6 and 7).
	assert.Less(t, intakeCallCount, numBeads,
		"loop must stop claiming after threshold is reached; intake should not be called on all beads")
}

// TestDrainLoop_ResetsCounterOnDifferentFingerprint is AC #4: Alternating or
// differing fingerprints below the threshold do NOT escalate.
func TestDrainLoop_ResetsCounterOnDifferentFingerprint(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	// Create multiple beads that will fail with different fingerprints
	// (alternating between two different error reasons).
	numBeads := 8
	var beadIDs []string
	for i := 0; i < numBeads; i++ {
		b := &bead.Bead{
			ID:       "ddx-preclaim-alt-" + string(rune(i)),
			Title:    "preclaim alternate test " + string(rune(i)),
			Priority: 0,
		}
		require.NoError(t, store.Create(b))
		beadIDs = append(beadIDs, b.ID)
	}

	intakeCallCount := 0
	reasonSequence := []string{
		"error_type_a",
		"error_type_b",
		"error_type_a",
		"error_type_b",
		"error_type_a",
		"error_type_b",
		"error_type_a",
		"error_type_b",
	}

	// Pre-claim intake hook that returns alternating error reasons.
	intakeHook := func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
		var reason string
		if intakeCallCount < len(reasonSequence) {
			reason = reasonSequence[intakeCallCount]
		}
		intakeCallCount++
		return PreClaimIntakeResult{
			Outcome: PreClaimIntakeError,
			Reason:  reason,
			Detail:  "alternating error " + reason,
		}, nil
	}

	executor := ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
		return ExecuteBeadReport{
			BeadID:    beadID,
			Status:    ExecuteBeadStatusSuccess,
			ResultRev: "rev",
		}, nil
	})

	opts := config.TestLoopConfigOpts{
		Assignee:                           "test-worker",
		BeadQualityLintBlockThresholdScore: 0,
	}
	rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))

	var eventLog bytes.Buffer
	rt := ExecuteBeadLoopRuntime{
		Once:                            false,
		ProjectRoot:                     store.ProjectRoot(),
		SessionID:                       "test-session",
		WorkerID:                        "test-worker",
		Log:                             &eventLog,
		EventSink:                       &eventLog,
		PreClaimIntakeHook:              intakeHook,
		PreClaimWarnRepeatThreshold:     5,
		PreClaimTimeout:                 5 * time.Second,
	}

	worker := &ExecuteBeadWorker{
		Store:    store,
		Executor: executor,
	}

	result, err := worker.Run(context.Background(), rcfg, rt)

	require.NoError(t, err)
	require.NotNil(t, result)

	// AC #4: With alternating fingerprints, the loop must NOT escalate.
	assert.NotEqual(t, "OperatorAttention", result.StopCondition,
		"loop must not escalate when fingerprints alternate below threshold")
	assert.Nil(t, result.OperatorAttention,
		"loop must not set OperatorAttention when fingerprints differ")

	// The loop should have processed all (or nearly all) beads without
	// escalating, confirming the counter resets on different fingerprints.
	assert.Equal(t, numBeads, intakeCallCount,
		"loop must process all beads when fingerprints differ")
}

// TestPreClaimWarnRepeatState_ResetsOnClaim is AC #2: The threshold N is
// configurable with a documented default of 5; the counter resets when a
// different fingerprint is observed or a claim succeeds.
func TestPreClaimWarnRepeatState_ResetsOnClaim(t *testing.T) {
	state := &preClaimWarnRepeatState{}

	// Simulate two identical warn fingerprints on distinct beads.
	fp := "abc123"

	// First warn on bead-1.
	assert.False(t, appendPreClaimIntakeWarning(
		nil,
		func(eventType string, data map[string]any) {},
		state,
		5,
		"bead-1",
		"error_a",
		"detail 1",
		time.Now(),
	))
	assert.Equal(t, 1, state.Count)
	assert.Equal(t, fp, state.Fingerprint)

	// Second warn on bead-2 (same fingerprint).
	assert.False(t, appendPreClaimIntakeWarning(
		nil,
		func(eventType string, data map[string]any) {},
		state,
		5,
		"bead-2",
		"error_a",
		"detail 2",
		time.Now(),
	))
	assert.Equal(t, 2, state.Count)

	// Now reset (simulating successful claim).
	resetPreClaimWarnState(state)
	assert.Equal(t, 0, state.Count)
	assert.Equal(t, "", state.Fingerprint)

	// After reset, a new fingerprint should start at count 1.
	assert.False(t, appendPreClaimIntakeWarning(
		nil,
		func(eventType string, data map[string]any) {},
		state,
		5,
		"bead-3",
		"error_b",
		"detail 3",
		time.Now(),
	))
	assert.Equal(t, 1, state.Count)
}

// TestPreClaimWarnRepeatState_ConfigurableThreshold is AC #2: The threshold N
// is configurable with a documented default of 5.
func TestPreClaimWarnRepeatState_ConfigurableThreshold(t *testing.T) {
	state := &preClaimWarnRepeatState{}

	emit := func(eventType string, data map[string]any) {}

	thresholds := []int{1, 3, 5, 10}

	for _, threshold := range thresholds {
		state = &preClaimWarnRepeatState{}

		// Add threshold - 1 warns (should not escalate).
		for i := 0; i < threshold-1; i++ {
			escalated := appendPreClaimIntakeWarning(
				nil,
				emit,
				state,
				threshold,
				"bead-"+string(rune(i)),
				"error_type",
				"detail",
				time.Now(),
			)
			assert.False(t, escalated, "should not escalate at threshold-1")
		}

		// Add one more (should escalate at threshold).
		escalated := appendPreClaimIntakeWarning(
			nil,
			emit,
			state,
			threshold,
			"bead-threshold",
			"error_type",
			"detail",
			time.Now(),
		)
		assert.True(t, escalated,
			"should escalate exactly at threshold=%d", threshold)
	}
}

