// appendPreClaimIntakeWarning updates the pre-claim warn state tracking N
// consecutive identical fingerprints. It emits a warn event via the emit
// callback and returns true if escalation (operator attention) is warranted.
//
// When escalation returns true, the caller must emit an operator-attention
// event, set a terminal result condition, and break the drain loop.
//
// The function creates a fingerprint from the rule_id, reason, decision_source,
// policy_mode, decision, and suggested_action. It tracks distinct bead IDs
// and resets the counter when a different fingerprint is observed.
func appendPreClaimIntakeWarning(
	store BeadReader,
	emit func(eventType string, data map[string]any),
	state *preClaimWarnRepeatState,
	threshold int,
	beadID, reason, detail string,
	at time.Time,
) bool {
	if store == nil || emit == nil || state == nil || threshold <= 0 {
		return false
	}

	// Create the warn fingerprint using the same vocabulary as the
	// pre_claim_intake.warn event body.
	fingerprint := readinessDecisionFingerprint(
		"pre_claim_intake",
		reason,
		"pre_claim_intake",
		"warn-only",
		"warn",
		"continue with implementation; operator attention is reserved for explicit targeted execution",
	)

	// If this is a different fingerprint, reset the counter.
	if fingerprint != state.Fingerprint {
		state.Fingerprint = fingerprint
		state.Count = 0
		state.DistinctBeadIDs = make(map[string]struct{})
		state.ExampleDetail = ""
	}

	// Record this bead if not already seen with this fingerprint.
	if _, ok := state.DistinctBeadIDs[beadID]; !ok {
		state.Count++
		state.DistinctBeadIDs[beadID] = struct{}{}
		if state.ExampleDetail == "" {
			state.ExampleDetail = detail
		}
	}

	// Emit a warn event for this candidate.
	eventBody := readinessDecisionBody(
		"pre_claim_intake",
		reason,
		"pre_claim_intake",
		"warn-only",
		"warn",
		"continue with implementation; operator attention is reserved for explicit targeted execution",
		map[string]any{
			"bead_id": beadID,
			"detail":  detail,
		},
	)
	emit("pre_claim_intake.warn", eventBody)

	// Check escalation threshold: N consecutive distinct beads with the
	// same fingerprint.
	if state.Count >= threshold {
		return true
	}
	return false
}

